import{_ as a,o as t,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"63. Purchased Leave","description":"","frontmatter":{"title":"63. Purchased Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","purchased-leave","preliminary"]},"headers":[],"relativePath":"ebas/mspp/leave/63-purchased-leave.md","filePath":"ebas/mspp/leave/63-purchased-leave.md"}'),n={name:"ebas/mspp/leave/63-purchased-leave.md"};function o(l,e,i,p,h,d){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_63-purchased-leave" tabindex="-1">63. Purchased Leave <a class="header-anchor" href="#_63-purchased-leave" aria-label="Permalink to &quot;63. Purchased Leave&quot;">​</a></h1><p><strong>a.</strong> Employees may apply for and be granted Purchased Leave employment arrangements subject to agreement with the Employer, such agreement not being unreasonably withheld.</p><p><strong>b.</strong> These arrangements are defined as meaning a situation where an Employee takes up to an additional 4 weeks&#39; leave per annum in addition to all other leave entitlements but is paid either 48/52, 49/52, 50/52 or 51/52 of the weekly base rate prescribed by this Agreement for each week during which their employment is subject to these arrangements.</p><p><strong>c.</strong> Other entitlements will be unaffected by these arrangements.</p><p><strong>d.</strong> Where an Employee applies for leave pursuant to this clause the Employer shall respond to such request within four weeks.</p><p>Plain language terms: 48/52, buying leave, extra leave.</p>',6)])])}const u=a(n,[["render",o]]);export{m as __pageData,u as default};
